def get_queryset(request: OtovoRequest):
    from django.db.models import Exists, OuterRef

    qs = (
        get_user_model()
        .objects.filter(is_staff=True)
        .annotate(is_enrolled=Exists(FieldSalesAgent.objects.filter(user=OuterRef('pk'))))
        .order_by('is_enrolled', 'email')
        .distinct()
    )

    user = request.user
    if user.is_superuser:
        return qs

    business_units = user.staff_profile.business_units.all()

    return qs.filter(staff_profile__business_units__in=business_units)


class FieldSalesAgentListView(StaffRequiredMixin, OtovoListView):
    template_name = 'fieldsales/field_agent_list.html'
    context_object_name = 'agents'
    model = FieldSalesAgent
    default_order = 'created_at'
    paginate_by = 15
    title = _('List: All field agents')
    select_related = ('user',)

    filter_class = FieldSalesAgentFilter

    if TYPE_CHECKING:
        request: OtovoRequest

    def get_context_data(self, **kwargs: Any) -> dict:
        ctx = super().get_context_data(**kwargs)

        def can_resend(ts: datetime | None):
            if not ts:
                return True
            elapsed = timezone.now() - ts
            return elapsed.total_seconds() > 60 * 5

        ctx['weekday_enum'] = Weekday
        ctx['can_resend'] = can_resend
        return ctx

    def get_base_queryset(self):
        today = datetime.combine(timezone.now().date(), time.min, tzinfo=UTC_TZ)
        current_monday = today - timedelta(days=today.weekday())
        next_monday = current_monday + timedelta(days=7)
        current_week = DateTimeTZRange(current_monday, next_monday)
        next_week = DateTimeTZRange(next_monday, next_monday + timedelta(days=7))
        return (
            FieldSalesAgent.all_for_staff_user(self.request.user)
            .annotate(
                events_current_week=Count(
                    'calendar_events',
                    filter=Q(
                        calendar_events__slot__contained_by=current_week,
                        calendar_events__deleted_at__isnull=True,
                    ),
                ),
                events_next_week=Count(
                    'calendar_events',
                    filter=Q(
                        calendar_events__slot__contained_by=next_week,
                        calendar_events__deleted_at__isnull=True,
                    ),
                ),
                latest_auth_sent=Event.objects.filter(
                    object_id=OuterRef('id'), name='google_calendar_authentication_email_sent'
                )
                .order_by('-created_at')
                .values('created_at')[:1],
            )
            .prefetch_related(
                Prefetch(
                    'schedules',
                    queryset=FieldSalesSchedule.objects.select_related('named_zone').defer(
                        'named_zone__polygon'
                    ),
                )
            )
            .select_related('business_unit')
        )


class FieldSalesScheduleCreateView(StaffRequiredMixin, FormView):
    form_class = FieldSalesScheduleForm
    template_name = 'fieldsales/field_agent_form.html'

    if TYPE_CHECKING:
        request: OtovoRequest

    def post(self, request, *args, **kwargs):
        form = self.get_form()
        if not form.is_valid():
            messages.error(self.request, form.errors.as_text())
            return self.form_invalid(form)

        user = form.cleaned_data.get('user')
        schedule: FieldSalesSchedule = form.save(commit=False)
        schedule.base_address = form.cleaned_data['base_address']

        if confilict := FieldSalesSchedule.objects.filter(
            agent__user=user, working_days__overlap=schedule.working_days
        ).first():
            overlapping_days = sorted(set(schedule.working_days) & set(confilict.working_days))
            days = ', '.join(str(x) for x in overlapping_days)
            form.add_error(
                'working_days',
                f'Agent has existing schedule with overlapping days: {days}',
            )
            return self.form_invalid(form)

        with transaction.atomic():
            agent, __ = FieldSalesAgent.objects.get_or_create(
                user=user,
                defaults={'business_unit': form.cleaned_data.get('business_unit')},
            )
            schedule.agent = agent
            schedule.active_period = DateTimeTZRange(timezone.now(), None)
            schedule.save()

        # Send mail to the agent where we ask for permission to access their calendar
        if not agent.is_authenticated:
            agent.send_authentication_link_email()
        messages.success(self.request, _(f'Field agent {agent.user.email} added successfully.'))
        return redirect(reverse('fieldsales:index'))

    def get_context_data(self, **kwargs: Any) -> dict:
        ctx = super().get_context_data(**kwargs)
        ctx['title'] = _('Field agents: Add new')
        return ctx

    def get_initial(self):
        initial = super().get_initial()
        initial.update(
            {
                'start_time': '08:00',
                'end_time': '16:00',
                'start_driving_time': '08:00',
                'end_driving_time': '16:00',
                'working_days': [day for day, __ in Weekday.choices()],
                'business_unit': self.request.user.staff_profile.primary_business_unit,
            }
        )
        return initial

    def get_form_kwargs(self):
        kwargs = super().get_form_kwargs()
        kwargs.update(
            {
                'custom_queryset': [
                    (
                        'named_zone',
                        NamedZone.all_heads()
                        .select_related('business_unit')
                        .filter(business_unit__in=BusinessUnit.all_for_user(self.request.user))
                        .order_by('business_unit', 'name'),
                    ),
                    ('business_unit', BusinessUnit.all_for_user(self.request.user)),
                ],
            }
        )
        return kwargs


@login_required
def enroll_user(request: OtovoRequest):
    logger.info(f'Enrolling user {request.user.username} into field sales program')

    (agent, _) = FieldSalesAgent.objects.get_or_create(
        user=request.user,
        defaults={'business_unit': request.user.staff_profile.primary_business_unit},
    )

    config = get_config()

    flow = google_auth_oauthlib.flow.Flow.from_client_config(
        config,
        scopes=['https://www.googleapis.com/auth/calendar'],
    )

    flow.redirect_uri = urljoin(
        request.scheme + '://' + request.get_host(),  # type: ignore
        reverse('fieldsales:calendar_oauth_callback', urlconf='cloud.urls'),
    )

    authorization_url, state = flow.authorization_url(
        access_type='offline',
        include_granted_scopes='true',
        login_hint=request.user.username,
        prompt='consent',
    )

    agent.google_auth_state = state
    agent.save(update_fields=['updated_at', 'google_auth_state'])
    return redirect(authorization_url)


