class FieldSalesServiceAreaCreateView(OtovoPermissionRequiredMixin, StaffRequiredMixin, CreateView):
    permission_required = 'fieldsales.add_fieldsalesservicearea'
    form_class = FieldSalesServiceAreaCreateForm
    template_name = 'fieldsales/service_areas/form.html'
    title = _('Field sales service area: Create new')

    if TYPE_CHECKING:
        request: OtovoRequest
        named_zones: QuerySet[NamedZone]

    def dispatch(self, request, *args, **kwargs):
        self.named_zones = (
            NamedZone.all_heads()
            .select_related('business_unit')
            .filter(business_unit__in=BusinessUnit.all_for_user(self.request.user))
            .order_by('business_unit', 'name')
        )
        if not self.named_zones.exists():
            zones_url = reverse('location:zones')
            messages.error(
                request,
                'No zones available in your business units. You can manage zones '
                f'<a target="_blank" href="{zones_url}">here</a>.',
                extra_tags='safe',
            )
            return redirect(reverse('fieldsales:service-areas-list'))
        return super().dispatch(request, *args, **kwargs)

    def get_form_kwargs(self) -> dict[str, Any]:
        kwargs = super().get_form_kwargs()
        kwargs['custom_queryset'] = [('named_zone', self.named_zones)]
        return kwargs

    def get_context_data(self, **kwargs: dict[str, Any]) -> dict[str, Any]:
        context = super().get_context_data(**kwargs)
        context['named_zone_feature_collection'] = queryset_to_feature_collection(
            queryset=self.named_zones,
            geometry_field='polygon',
            fields=('id', 'name'),
        )
        return context

    def form_valid(self, form):
        service_area: FieldSalesServiceArea = form.save(commit=False)
        business_unit = service_area.named_zone.business_unit

        tzinfo = ZoneInfo(business_unit.config.default_timezone)
        service_area.valid_from = datetime.combine(form.cleaned_data['valid_from'], time.min, tzinfo)
        if valid_to := form.cleaned_data['valid_to']:
            service_area.valid_to = datetime.combine(valid_to, time.max, tzinfo)

        service_area.business_unit = service_area.named_zone.business_unit

        try:
            with transaction.atomic():
                service_area.save()
                Event.object_created(service_area, user=self.request.user)
        except IntegrityError:
            form.add_error(
                None,
                _('A service area already exists for the selected zone and time period.'),
            )
            return self.form_invalid(form)

        messages.success(self.request, _('Field sales service area created successfully'))
        return redirect(reverse('fieldsales:service-areas-list'))


