@staff_required
@permission_required('fieldsales.add_fieldsalesservicearea')
def hx_update_service_area(request: OtovoRequest, pk: UUID) -> HttpResponse:
    service_area = get_object_or_404(FieldSalesServiceArea, pk=pk)
    context: dict[str, Any] = {'service_area': service_area}

    form = FieldSalesServiceAreaUpdateForm(
        request.POST or None,
        valid_from_date=service_area.valid_from.date(),
        initial={
            'valid_to': service_area.valid_to.date() if service_area.valid_to else None,
        },
    )

    if request.method == 'POST' and form.is_valid():
        business_unit = service_area.named_zone.business_unit
        tzinfo = ZoneInfo(business_unit.config.default_timezone)
        valid_to_date = form.cleaned_data['valid_to']
        valid_to: datetime | None = None

        if valid_to_date is not None:
            valid_to = datetime.combine(valid_to_date, time.max, tzinfo)

        service_area.change_property(
            field=FieldSalesServiceArea.valid_to, new_value=valid_to, user=request.user
        )
        messages.success(request, _('Service area updated successfully'))

    elif not request.GET.get('cancel'):
        context['form'] = form

    return TemplateResponse(request, 'fieldsales/service_areas/row_hx.html', context)
