from __future__ import annotations

from typing import TYPE_CHECKING

from django.db.models import Q
from django.utils import timezone

import django_filters

from cloud.businessunits.models.businessunit import BusinessUnit
from cloud.fieldsales.models import FieldSalesAgent, FieldSalesServiceArea
from cloud.financial.transfer_pricing.filters import get_central_business_units
from cloud.installerapp.filters import BooleanFilterWithEmptyChoice

if TYPE_CHECKING:
    from django.db.models import QuerySet


class FieldSalesAgentFilter(django_filters.FilterSet):
    ordering = django_filters.OrderingFilter(fields=['agent'])
    business_unit = django_filters.ModelChoiceFilter(
        label='Business unit',
        queryset=get_central_business_units(),
        field_name='business_unit',
    )

    class Meta:
        model = FieldSalesAgent
        fields = ('business_unit',)


class FieldSalesServiceAreaFilter(django_filters.FilterSet):
    business_unit = django_filters.ModelChoiceFilter(
        label='Market',
        queryset=lambda request: BusinessUnit.all_for_user(request.user, only_central_units=True),
    )
    is_active = BooleanFilterWithEmptyChoice(
        method='filter_is_active',
        label='Is active',
    )

    class Meta:
        model = FieldSalesServiceArea()
        fields = ('business_unit',)

    @staticmethod
    def filter_is_active(
        queryset: QuerySet[FieldSalesServiceArea], _, value: str
    ) -> QuerySet[FieldSalesServiceArea]:
        if value == '':
            return queryset

        now = timezone.now()

        is_active_filter = Q(
            valid_from__lte=now,
        ) & (Q(valid_to__isnull=True) | Q(valid_to__gte=now))

        if bool(value):
            return queryset.filter(is_active_filter)
        return queryset.exclude(is_active_filter)
